// Wrap the changelog response so it matches the shape
// the Classify Change node expects: json.changelog.histories
return $input.all().map(item => {
  return {
    json: {
      changelog: {
        histories: item.json.values || []
      }
    }
  };
});

// Classify what changed on each Jira issue using the changelog.
// Produces granular raw_event_type and a contextual body that
// describes the *change*, not just the full ticket description.

const TWO_MINUTES_MS = 2 * 60 * 1000;
const now = Date.now();

const results = [];

for (const item of $input.all()) {
  const json = item.json;
  const fields = json.fields || {};
  const created = fields.created;
  const updated = fields.updated;

  // --- Determine if this is a brand-new issue ---
  const isNew = created === updated;

  // --- Parse changelog for recent changes ---
  const changelog = json.changelog || {};
  const histories = changelog.histories || [];

  // Only look at changes from the last 2 minutes (matching our poll window)
  const recentChanges = histories.filter(h => {
    const changeTime = new Date(h.created).getTime();
    return (now - changeTime) < TWO_MINUTES_MS;
  });

  // Collect changed fields from recent history
  const changedFields = [];
  const fieldChanges = {};  // { fieldName: { from, to } }
  for (const history of recentChanges) {
    for (const changeItem of (history.items || [])) {
      const field = changeItem.field;
      changedFields.push(field);
      fieldChanges[field] = {
        from: changeItem.fromString || changeItem.from || '',
        to: changeItem.toString || changeItem.to || ''
      };
    }
  }

  // --- Classify the change type ---
  let rawEventType = 'issue_updated';  // fallback
  let body = '';
  let changeType = 'generic_update';
  let previousStatus = null;
  let newStatus = null;
  let resolution = null;

  if (isNew) {
    // Brand-new issue
    rawEventType = 'issue_created';
    changeType = 'created';
    const desc = fields.description;
    body = typeof desc === 'string'
      ? desc
      : (desc?.content?.[0]?.content?.[0]?.text || fields.summary || '');

  } else if (fieldChanges['status']) {
    // Status transition
    const from = fieldChanges['status'].from;
    const to = fieldChanges['status'].to;
    previousStatus = from;
    newStatus = to;

    const closedStatuses = ['done', 'closed', 'resolved', 'cancelled'];
    const toL = to.toLowerCase();
    const fromL = from.toLowerCase();

    if (closedStatuses.includes(toL) && !closedStatuses.includes(fromL)) {
      // Ticket closed/resolved
      rawEventType = 'issue_resolved';
      changeType = 'resolved';
      resolution = fields.resolution?.name || null;
      body = `Ticket ${toL}: ${from} → ${to}.`;
      if (resolution) body += ` Resolution: ${resolution}.`;
      // Append latest comment if any (often contains resolution notes)
      const comments = fields.comment?.comments;
      if (comments?.length) {
        const latest = comments[comments.length - 1];
        const commentBody = typeof latest.body === 'string'
          ? latest.body
          : (latest.body?.content?.[0]?.content?.[0]?.text || '');
        if (commentBody) body += `\n\nLatest comment (${latest.author?.displayName || 'Unknown'}): ${commentBody}`;
      }

    } else if (closedStatuses.includes(fromL) && !closedStatuses.includes(toL)) {
      // Ticket reopened
      rawEventType = 'issue_reopened';
      changeType = 'reopened';
      body = `Ticket reopened: ${from} → ${to}.`;

    } else {
      // Regular status transition (e.g., To Do → In Progress)
      rawEventType = 'issue_status_changed';
      changeType = 'status_changed';
      body = `Status changed: ${from} → ${to}.`;
    }

  } else if (fieldChanges['assignee']) {
    // Reassignment
    rawEventType = 'issue_assigned';
    changeType = 'assigned';
    const from = fieldChanges['assignee'].from || 'Unassigned';
    const to = fieldChanges['assignee'].to || 'Unassigned';
    body = `Assignee changed: ${from} → ${to}.`;

  } else if (fieldChanges['priority']) {
    // Priority change
    rawEventType = 'issue_priority_changed';
    changeType = 'priority_changed';
    body = `Priority changed: ${fieldChanges['priority'].from} → ${fieldChanges['priority'].to}.`;

  } else {
    // Check if there's a new comment (comments don't always appear in changelog)
    const comments = fields.comment?.comments;
    if (comments?.length) {
      const latest = comments[comments.length - 1];
      const commentTime = new Date(latest.created).getTime();
      if ((now - commentTime) < TWO_MINUTES_MS) {
        rawEventType = 'issue_commented';
        changeType = 'commented';
        const commentBody = typeof latest.body === 'string'
          ? latest.body
          : (latest.body?.content?.[0]?.content?.[0]?.text || '');
        body = `New comment from ${latest.author?.displayName || 'Unknown'}:\n${commentBody}`;
      }
    }

    // Fallback: summarize what fields changed
    if (rawEventType === 'issue_updated' && changedFields.length > 0) {
      changeType = 'fields_updated';
      const summaries = Object.entries(fieldChanges).map(
        ([f, c]) => `${f}: ${c.from || '(empty)'} → ${c.to || '(empty)'}`
      );
      body = `Fields updated:\n${summaries.join('\n')}`;
    } else if (rawEventType === 'issue_updated') {
      // No changelog entries found — possibly a re-poll of same state
      changeType = 'no_change_detected';
      body = `Issue polled with no detectable changes. Current status: ${fields.status?.name || 'Unknown'}.`;
    }
  }

  // --- Build the full description for metadata reference ---
  const fullDescription = typeof fields.description === 'string'
    ? fields.description
    : (fields.description?.content?.[0]?.content?.[0]?.text || '');

  // --- Pick the actor ---
  // For commented events, use the commenter. For status changes, try the
  // changelog author. Otherwise fall back to reporter/assignee.
  let actorName = fields.reporter?.displayName || 'Unknown';
  let actorEmail = fields.reporter?.emailAddress || '';
  let actorHandle = fields.reporter?.name || fields.reporter?.accountId || '';

  if (rawEventType === 'issue_commented') {
    const comments = fields.comment?.comments;
    if (comments?.length) {
      const latest = comments[comments.length - 1];
      actorName = latest.author?.displayName || actorName;
      actorEmail = latest.author?.emailAddress || actorEmail;
      actorHandle = latest.author?.name || latest.author?.accountId || actorHandle;
    }
  } else if (recentChanges.length > 0) {
    // Use the author of the most recent changelog entry
    const lastChange = recentChanges[recentChanges.length - 1];
    if (lastChange.author) {
      actorName = lastChange.author.displayName || actorName;
      actorEmail = lastChange.author.emailAddress || actorEmail;
      actorHandle = lastChange.author.name || lastChange.author.accountId || actorHandle;
    }
  }

  results.push({
    json: {
      event_id: 'evt_jira_' + json.id + '_' + new Date(updated || Date.now()).getTime(),
      timestamp: updated || new Date().toISOString(),
      source: {
        platform: 'jira',
        connection_id: $workflow.id,
        raw_event_type: rawEventType
      },
      actor: {
        name: actorName,
        email: actorEmail,
        platform_handle: actorHandle
      },
      subject: {
        type: 'ticket',
        id: json.key || '',
        title: fields.summary || '',
        url: json.self ? json.self.split('/rest/')[0] + '/browse/' + json.key : null
      },
      content: {
        body: body,
        attachments: [],
        metadata: {
          jira_project: fields.project?.key,
          jira_labels: fields.labels,
          jira_priority: fields.priority?.name,
          jira_status: fields.status?.name,
          jira_issue_type: fields.issuetype?.name,
          jira_assignee: fields.assignee?.emailAddress,
          jira_reporter: fields.reporter?.emailAddress,
          jira_change_type: changeType,
          jira_previous_status: previousStatus,
          jira_new_status: newStatus,
          jira_resolution: resolution || fields.resolution?.name || null,
          jira_changed_fields: changedFields,
          jira_description: fullDescription
        }
      }
    }
  });
}

return results;
